## Solution 1: Dependency Validation with Graceful Degradation (Recommended)

Implement a pre-flight dependency checker that validates all required binaries before execution, with clear warnings when tools are missing.

```python
import shutil
import subprocess
from typing import Dict, List, Optional
from dataclasses import dataclass
from enum import Enum

class ToolStatus(Enum):
    AVAILABLE = "available"
    MISSING = "missing"
    ERROR = "error"

@dataclass
class ToolConfig:
    name: str
    binary: str
    install_cmd: str
    optional: bool = False

class DependencyManager:
    def __init__(self):
        self.tools = {
            "subfinder": ToolConfig("subfinder", "subfinder", "go install github.com/projectdiscovery/subfinder/v2/cmd/subfinder@latest"),
            "nmap": ToolConfig("nmap", "nmap", "apt install nmap"),
            "whatweb": ToolConfig("whatweb", "whatweb", "apt install whatweb"),
        }
        self.status: Dict[str, ToolStatus] = {}

    def check_dependencies(self) -> Dict[str, ToolStatus]:
        """Check all tool dependencies and return status map."""
        for tool_name, config in self.tools.items():
            self.status[tool_name] = self._check_binary(config)
        return self.status

    def _check_binary(self, config: ToolConfig) -> ToolStatus:
        """Check if a binary exists and is executable."""
        if shutil.which(config.binary):
            try:
                # Verify binary actually runs (not just exists)
                result = subprocess.run(
                    [config.binary, "--version"],
                    capture_output=True,
                    timeout=5
                )
                return ToolStatus.AVAILABLE if result.returncode == 0 else ToolStatus.ERROR
            except (subprocess.TimeoutExpired, OSError):
                return ToolStatus.ERROR
        return ToolStatus.MISSING

    def validate_critical(self) -> bool:
        """Ensure all non-optional tools are available."""
        for tool_name, config in self.tools.items():
            if not config.optional and self.status.get(tool_name) != ToolStatus.AVAILABLE:
                return False
        return True

    def get_missing_tools(self) -> List[str]:
        """Return list of missing tool names."""
        return [
            name for name, status in self.status.items() 
            if status == ToolStatus.MISSING
        ]

    def generate_install_script(self) -> str:
        """Generate installation commands for missing tools."""
        commands = []
        for tool_name, status in self.status.items():
            if status == ToolStatus.MISSING:
                commands.append(self.tools[tool_name].install_cmd)
        return "\n".join(commands)


class TargetProfiler:
    def __init__(self):
        self.dep_manager = DependencyManager()
        self.results = {}

    def profile(self, target: str) -> Dict:
        """Run profiling with dependency checks."""
        # Pre-flight check
        status = self.dep_manager.check_dependencies()

        if not self.dep_manager.validate_critical():
            missing = self.dep_manager.get_missing_tools()
            raise RuntimeError(
                f"Missing critical dependencies: {missing}\n"
                f"Install with:\n{self.dep_manager.generate_install_script()}"
            )

        # Run available tools with graceful degradation
        self.results = {
            "target": target,
            "subdomains": self._run_subfinder(target) if status["subfinder"] == ToolStatus.AVAILABLE else None,
            "ports": self._run_nmap(target) if status["nmap"] == ToolStatus.AVAILABLE else None,
            "webtech": self._run_whatweb(target) if status["whatweb"] == ToolStatus.AVAILABLE else None,
            "missing_tools": self.dep_manager.get_missing_tools()
        }

        return self.results

    def _run_subfinder(self, target: str) -> Optional[Dict]:
        """Execute subfinder with proper error handling."""
        try:
            result = subprocess.run(
                ["subfinder", "-d", target, "-json"],
                capture_output=True,
                text=True,
                timeout=300
            )
            if result.returncode != 0:
                return {"error": result.stderr, "data": None}
            return {"error": None, "data": result.stdout}
        except subprocess.TimeoutExpired:
            return {"error": "Timeout", "data": None}
        except FileNotFoundError:
            return {"error": "Binary not found", "data": None}

    def _run_nmap(self, target: str) -> Optional[Dict]:
        """Execute nmap with proper error handling."""
        try:
            result = subprocess.run(
                ["nmap", "-sV", "-oX", "-", target],
                capture_output=True,
                text=True,
                timeout=600
            )
            return {"error": None, "data": result.stdout}
        except Exception as e:
            return {"error": str(e), "data": None}

    def _run_whatweb(self, target: str) -> Optional[Dict]:
        """Execute whatweb with proper error handling."""
        try:
            result = subprocess.run(
                ["whatweb", "--json", target],
                capture_output=True,
                text=True,
                timeout=300
            )
            return {"error": None, "data": result.stdout}
        except Exception as e:
            return {"error": str(e), "data": None}
